import React, { useState, useMemo, useCallback } from 'react';
import { Menu } from 'lucide-react';
import { useWorkflow, useCascade } from '@cascaide-ts/react';
import { v4 as uuidv4 } from 'uuid';
import { Sidebar } from './sidebar';
import { InputBar } from './input.tsx';
import { MessageList } from './message-list';
import { Spawns } from './types';
import { CanonicalMessage } from './types';
import { RightSidebar } from './rightSidebar';

// ── Types ────────────────────────────────────────────────────────────────────

interface ChatProps {
  nodeId: string;
}

type AgentType =
  | 'hotelSupervisorNode'
  | 'searchAgentNode'
  | 'recursiveSearchAgentNode';

const LAPIS = '#26619C';

// ── Main Component ───────────────────────────────────────────────────────────

export default function Chat({ nodeId }: ChatProps) {
  const [input, setInput] = useState('');
  const userId = 'guest-id';
  const userName = 'there';

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isSidebarExpanded, setIsSidebarExpanded] = useState(false);

  const { addActiveNode } = useWorkflow(nodeId);

  const [chatId, setChatId] = useState<string>(uuidv4());

  const { cascadeState, isComplete } = useCascade(chatId);

  const [pendingUserMessage, setPendingUserMessage] = useState<CanonicalMessage | null>(null);

  const [selectedAgent, setSelectedAgent] = useState<AgentType>('hotelSupervisorNode');

  const isProcessing = useMemo(
    () => !isComplete && !!cascadeState,
    [isComplete, cascadeState]
  );

  // ── Derive conversationMessages from cascade state ───────────────────────

  const conversationMessages = useMemo<CanonicalMessage[]>(() => {
    const base = (cascadeState?.history as CanonicalMessage[]) ?? [];

    if (!pendingUserMessage) return base;

    const alreadySynced = base.some(
      (m) => m.role === 'user' && m.content === pendingUserMessage.content
    );

    if (alreadySynced) {
      setTimeout(() => setPendingUserMessage(null), 0);
      return base;
    }

    return [...base, pendingUserMessage];
  }, [cascadeState?.history, pendingUserMessage]);

  const currentChatHasUserMessages = useMemo(
    () => conversationMessages.some((m) => m.role === 'user'),
    [conversationMessages]
  );

  // ── Sidebar ──────────────────────────────────────────────────────────────

  const toggleSidebarExpansion = useCallback(() => {
    setIsSidebarExpanded((prev) => !prev);
  }, []);

  const startNewChat = useCallback(() => {
    const newId = uuidv4();
    setChatId(newId);
    setPendingUserMessage(null);
    setInput('');
  }, []);

  const selectChat = useCallback(
    (id: string) => {
      if (id === chatId) return;
      setChatId(id);
      setPendingUserMessage(null);
      setInput('');
      // TODO: load selected chat history from persistent store
    },
    [chatId]
  );

  // Agent switch → start a fresh chat and pre-fill the starter prompt
  const handleAgentChange = useCallback(
    (agent: AgentType, starterPrompt: string) => {
      setSelectedAgent(agent);
      const newId = uuidv4();
      setChatId(newId);
      setPendingUserMessage(null);
      setInput(starterPrompt);
    },
    []
  );

  // ── Send user message ────────────────────────────────────────────────────

  const handleSendMessage = useCallback(
    async (message: string) => {
      if (!message.trim() || isProcessing || !userId) return;

      const newUserMessage: CanonicalMessage = {
        role: 'user',
        content: message.trim(),
      };

      setPendingUserMessage(newUserMessage);
      setInput('');

      // const updatedHistory = [...conversationMessages, newUserMessage];

      const spawns: Spawns = {
        [selectedAgent]: {
          cascadeId: chatId,
          history: [newUserMessage],
          //In Lite mode, set history: updatedHistory,
          userId,
        },
      };

      await addActiveNode(spawns);
    },
    [isProcessing, userId, addActiveNode, chatId, selectedAgent, conversationMessages]
  );

  // ── Tool response ────────────────────────────────────────────────────────

  const handleToolResponse = useCallback(
    async (toolMessage: CanonicalMessage) => {
      setInput('');
      // const updatedHistory = [...conversationMessages, toolMessage];

      const spawns: Spawns = {
        hotelSupervisorNode: {
          cascadeId: chatId,
          history: [toolMessage],
          // in lite mode, set history: updatedHistory,
          userId,
        },
      };

      await addActiveNode(spawns);
    },
    [addActiveNode, chatId, conversationMessages]
  );

  // ── Keyboard ─────────────────────────────────────────────────────────────

  const handleKeyPress = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage(input);
      }
    },
    [input, handleSendMessage]
  );

  const isEmptyChat = !currentChatHasUserMessages;

  return (
    <div className="w-screen h-screen flex overflow-hidden">

      {/* Sidebar */}
      <Sidebar
        history={[]}
        currentChatId={chatId}
        onNewChat={startNewChat}
        onSelectChat={selectChat}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        isExpanded={isSidebarExpanded}
        toggleExpansion={toggleSidebarExpansion}
      />

      {/* Main content */}
      <div className="flex-1 flex flex-col min-w-0 relative">

        {/* Mobile menu button */}
        {!isSidebarOpen && (
          <button
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden absolute top-5 left-6 z-50 p-2.5 rounded-full"
            style={{
              background: 'rgba(255,255,255,0.65)',
              backdropFilter: 'blur(12px)',
              border: '1px solid rgba(255,255,255,0.70)',
              boxShadow: '0 2px 12px rgba(38,97,156,0.10)',
            }}
          >
            <Menu className="w-5 h-5" style={{ color: LAPIS }} />
          </button>
        )}

        <div className="h-full w-full flex flex-col">
          {isEmptyChat ? (
            <div className="flex-1 flex flex-col items-center justify-center px-6 pb-16">
              <h1 className="text-5xl font-bold mb-8 text-slate-800">
                Hello <span style={{ color: LAPIS }}>{userName}</span>!
              </h1>

              {/* Agent picker + input live inside InputBar via the card grid */}
              <InputBar
                input={input}
                isProcessing={isProcessing}
                userId={userId}
                selectedAgent={selectedAgent}
                onAgentChange={handleAgentChange}
                onChange={setInput}
                onSend={() => handleSendMessage(input)}
                onKeyPress={handleKeyPress}
              />
            </div>
          ) : (
            <>
              <MessageList
                displayHistory={conversationMessages}
                userId={userId}
                addActiveNode={addActiveNode}
                handleToolResponse={handleToolResponse}
              />

              <div className="px-6 py-4">
                <div className="max-w-4xl mx-auto">
                  <InputBar
                    input={input}
                    isProcessing={isProcessing}
                    userId={userId}
                    compact
                    selectedAgent={selectedAgent}
                    onAgentChange={handleAgentChange}
                    onChange={setInput}
                    onSend={() => handleSendMessage(input)}
                    onKeyPress={handleKeyPress}
                  />
                </div>
              </div>
            </>
          )}
        </div>
      </div>
      {selectedAgent === 'recursiveSearchAgentNode' && <div className="hidden lg:block h-full">
        <RightSidebar />
      </div>
}


      {/* Mobile overlay */}
      {isSidebarOpen && (
        <div
          className="fixed inset-0 bg-black/20 z-40 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}
    </div>
  );
}

import { Send, Sparkles } from "lucide-react";
import { useState } from "react";

// ── Types ────────────────────────────────────────────────────────────────────

type AgentType =
  | 'hotelSupervisorNode'
  | 'searchAgentNode'
  | 'recursiveSearchAgentNode';

interface InputBarProps {
  input: string;
  isProcessing: boolean;
  userId: string;
  compact?: boolean;
  selectedAgent: AgentType;
  onAgentChange: (agent: AgentType, starterPrompt: string) => void;
  onChange: (value: string) => void;
  onSend: () => void;
  onKeyPress: (e: React.KeyboardEvent) => void;
}

// ── Constants ────────────────────────────────────────────────────────────────

const LAPIS = '#26619C';
const LAPIS_DARK = '#1F4E8C';

const AGENTS = [
  {
    id: 'hotelSupervisorNode' as AgentType,
    label: 'Hotel Booking Supervisor',
    description:
      'Orchestrates multiple sub-agents to search, compare, and book hotels. Two HITL steps.',
    starter: 'Find and help me book available hotels for next weekend, 2 guests',
  },
  {
    id: 'searchAgentNode' as AgentType,
    label: 'ReAct Search',
    description:
      'A reasoning + acting agent that searches the web iteratively. Great for factual lookups, current events, and research questions.',
    starter: 'What are the most popular AI models and their stregths and weaknesses?+',
  },
  {
    id: 'recursiveSearchAgentNode' as AgentType,
    label: 'Recursive ReAct Search',
    description:
      'Breaks complex queries into sub-questions and searches recursively. Use this for in-depth research that needs multiple angles.',
    starter: 'Give me a detailed report on the causes of World War 2, examined from the perspective of opposing sides',
  },
];

// ── Component ────────────────────────────────────────────────────────────────

export function InputBar({
  input,
  isProcessing,
  userId,
  compact = false,
  selectedAgent,
  onAgentChange,
  onChange,
  onSend,
  onKeyPress,
}: InputBarProps) {
  const [focused, setFocused] = useState(false);

  // Selects an agent and pre-fills the input with its starter prompt,
  // then immediately sends it.
  const handleAgentCard = (agent: (typeof AGENTS)[number]) => {
    onAgentChange(agent.id, agent.starter);
    onChange(agent.starter);
    // Small delay so the parent state settles before sending
    setTimeout(() => onSend(), 0);
  };

  return (
    <div className={compact ? 'w-full' : 'w-full max-w-3xl'}>

      {/* ── Input card ─────────────────────────────────────────────────────── */}
      <div
        className="rounded-2xl transition-all duration-200"
        style={{
          background: 'rgba(255,255,255,0.55)',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
          border: focused
            ? `1.5px solid ${LAPIS}55`
            : '1.5px solid rgba(255,255,255,0.70)',
          boxShadow: focused
            ? `0 8px 32px rgba(38,97,156,0.13), 0 2px 8px rgba(38,97,156,0.08)`
            : '0 4px 24px rgba(38,97,156,0.07), 0 1px 4px rgba(0,0,0,0.04)',
        }}
      >
        <div className="flex gap-3 items-end p-3">
          {/* Textarea */}
          <div className="flex-1 relative">
            <textarea
              value={input}
              onChange={(e) => onChange(e.target.value)}
              onKeyPress={onKeyPress}
              onFocus={() => setFocused(true)}
              onBlur={() => setFocused(false)}
              placeholder={
                compact
                  ? 'Ask away...'
                  : 'Ask about hotels, destinations, availability…'
              }
              disabled={isProcessing || !userId}
              rows={1}
              className={`
                w-full resize-none bg-transparent
                text-slate-800 placeholder-slate-400
                focus:outline-none
                disabled:cursor-not-allowed disabled:text-slate-400
                leading-relaxed text-[15px]
                ${compact ? 'py-1.5' : 'py-2'}
              `}
              style={{
                minHeight: compact ? '36px' : '44px',
                maxHeight: compact ? '150px' : '200px',
                height: 'auto',
              }}
              onInput={(e) => {
                const target = e.target as HTMLTextAreaElement;
                target.style.height = 'auto';
                target.style.height =
                  Math.min(target.scrollHeight, compact ? 150 : 200) + 'px';
              }}
            />
          </div>

          {/* Send button */}
          <button
            onClick={onSend}
            disabled={!input.trim() || isProcessing || !userId}
            className={`
              flex items-center gap-2 font-medium text-sm text-white rounded-xl
              transition-all duration-200 active:scale-[0.97]
              disabled:opacity-40 disabled:cursor-not-allowed disabled:shadow-none
              flex-shrink-0
              ${compact ? 'px-4 py-2' : 'px-5 py-2.5'}
            `}
            style={{
              backgroundColor: LAPIS,
              boxShadow: '0 4px 14px rgba(38,97,156,0.30)',
            }}
            onMouseEnter={(e) => {
              if (!(e.currentTarget as HTMLButtonElement).disabled)
                (e.currentTarget as HTMLButtonElement).style.backgroundColor = LAPIS_DARK;
            }}
            onMouseLeave={(e) => {
              (e.currentTarget as HTMLButtonElement).style.backgroundColor = LAPIS;
            }}
            title="Send Message"
          >
            <Send className="w-4 h-4" />
            {!compact && <span>Send</span>}
          </button>
        </div>
      </div>

      {/* ── Keyboard hint ──────────────────────────────────────────────────── */}
      <p className="mt-2 text-center text-xs text-slate-400">
        Press{' '}
        <kbd
          className="font-mono px-1.5 py-0.5 rounded text-[10px]"
          style={{
            background: 'rgba(255,255,255,0.6)',
            border: '1px solid rgba(38,97,156,0.15)',
            color: '#475569',
          }}
        >
          Enter
        </kbd>{' '}
        to send,{' '}
        <kbd
          className="font-mono px-1.5 py-0.5 rounded text-[10px]"
          style={{
            background: 'rgba(255,255,255,0.6)',
            border: '1px solid rgba(38,97,156,0.15)',
            color: '#475569',
          }}
        >
          Shift + Enter
        </kbd>{' '}
        for new line
      </p>

      {/* ── Agent cards — full mode only ───────────────────────────────────── */}
      {!compact && (
        <div className="mt-5 grid grid-cols-2 gap-2.5">
          {AGENTS.map((agent) => {
            const isSelected = selectedAgent === agent.id;
            return (
              <button
                key={agent.id}
                onClick={() => handleAgentCard(agent)}
                disabled={isProcessing || !userId}
                className="
                  group text-left rounded-xl px-4 py-3
                  transition-all duration-200
                  disabled:opacity-40 disabled:cursor-not-allowed
                  active:scale-[0.98]
                "
                style={{
                  background: isSelected
                    ? `rgba(38,97,156,0.08)`
                    : 'rgba(255,255,255,0.45)',
                  backdropFilter: 'blur(12px)',
                  WebkitBackdropFilter: 'blur(12px)',
                  border: isSelected
                    ? `1.5px solid ${LAPIS}55`
                    : '1.5px solid rgba(255,255,255,0.65)',
                  boxShadow: '0 2px 10px rgba(38,97,156,0.05)',
                }}
                onMouseEnter={(e) => {
                  const el = e.currentTarget as HTMLButtonElement;
                  el.style.border = `1.5px solid ${LAPIS}44`;
                  el.style.background = 'rgba(255,255,255,0.65)';
                  el.style.boxShadow = '0 4px 16px rgba(38,97,156,0.10)';
                }}
                onMouseLeave={(e) => {
                  const el = e.currentTarget as HTMLButtonElement;
                  el.style.border = isSelected
                    ? `1.5px solid ${LAPIS}55`
                    : '1.5px solid rgba(255,255,255,0.65)';
                  el.style.background = isSelected
                    ? `rgba(38,97,156,0.08)`
                    : 'rgba(255,255,255,0.45)';
                  el.style.boxShadow = '0 2px 10px rgba(38,97,156,0.05)';
                }}
              >
                {/* Label row */}
                <div className="flex items-center gap-1.5 mb-1">
                  <Sparkles size={11} style={{ color: LAPIS }} className="flex-shrink-0" />
                  <span
                    className="text-[11px] font-semibold uppercase tracking-wider"
                    style={{ color: LAPIS }}
                  >
                    {agent.label}
                  </span>
                </div>
                {/* Description */}
                <p className="text-[12px] text-slate-500 leading-snug mb-1.5 line-clamp-2">
                  {agent.description}
                </p>
                {/* Starter prompt preview */}
                <p className="text-[13px] text-slate-600 leading-snug line-clamp-2 italic">
                  "{agent.starter}"
                </p>
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { memo, useState, useMemo, useCallback } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeHighlight from 'rehype-highlight';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import { Wrench, ChevronDown, Loader2, Brain, Bot, CheckCircle2 } from 'lucide-react';
import { toolRegistry } from './message-list';
import type { CanonicalMessage, CanonicalToolCall } from './types';

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const LAPIS       = '#26619C';
const LAPIS_LIGHT = 'rgba(38,97,156,0.08)';
const LAPIS_BORDER = 'rgba(38,97,156,0.35)';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface MessageBubbleProps {
  message:           CanonicalMessage;
  userId:            string | undefined;
  delegationStatus?: 'pending' | 'complete' | null;
  onToolComplete:    (toolCallId: string, result: string) => Promise<void>;
  toolResults:       Record<string, CanonicalMessage>;
}

interface ToolBlockProps {
  value:             CanonicalToolCall[];
  delegationStatus?: 'pending' | 'complete' | null;
  onToolComplete:    (toolCallId: string, result: string) => Promise<void>;
  toolResults:       Record<string, CanonicalMessage>;
}

// ---------------------------------------------------------------------------
// AssistantAvatar
// ---------------------------------------------------------------------------

const AssistantAvatar = () => (
  <div
    className="flex-shrink-0 w-7 h-7 rounded-full flex items-center justify-center mt-0.5"
    style={{ backgroundColor: LAPIS }}
  >
    <Bot className="w-3.5 h-3.5 text-white" />
  </div>
);

// ---------------------------------------------------------------------------
// ReasoningBlock — collapsible, lapis accented
// ---------------------------------------------------------------------------

const ReasoningBlock = memo(({ value }: { value: string }) => {
  const [isOpen, setIsOpen] = useState(false);
  if (!value) return null;

  return (
    <div className="py-3 max-w-4xl mx-auto">
      <div className="flex gap-3 items-start">
        {/* Spacer to align with assistant messages */}
        <div className="w-7 flex-shrink-0" />
        <div className="flex-1 min-w-0">
          <div
            className="rounded-xl overflow-hidden transition-all duration-200"
            style={{
              background: 'rgba(255,255,255,0.45)',
              backdropFilter: 'blur(12px)',
              WebkitBackdropFilter: 'blur(12px)',
              border: `1px solid rgba(255,255,255,0.65)`,
              boxShadow: '0 2px 8px rgba(38,97,156,0.06)',
            }}
          >
            <button
              onClick={() => setIsOpen(prev => !prev)}
              className="w-full flex items-center gap-2 px-3 py-2.5 text-left transition-colors hover:bg-white/30"
            >
              <Brain className="w-3.5 h-3.5 flex-shrink-0" style={{ color: LAPIS }} />
              <span
                className="text-xs font-semibold uppercase tracking-wider flex-1"
                style={{ color: LAPIS }}
              >
                Reasoning
              </span>
              <ChevronDown
                className={`w-3.5 h-3.5 transition-transform duration-200`}
                style={{
                  color: LAPIS,
                  transform: isOpen ? 'rotate(180deg)' : 'rotate(0deg)',
                }}
              />
            </button>

            {isOpen && (
              <div
                className="px-3 pb-3 pt-0 border-t"
                style={{
                  borderColor: LAPIS_BORDER,
                  background: LAPIS_LIGHT,
                }}
              >
                <p className="text-xs text-slate-600 font-mono mt-2 whitespace-pre-wrap leading-relaxed">
                  {value}
                </p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
});
ReasoningBlock.displayName = 'ReasoningBlock';

// ---------------------------------------------------------------------------
// TextBlock — assistant prose with avatar
// ---------------------------------------------------------------------------

const TextBlock = memo(({ value }: { value: string }) => (
  <div className="py-3 max-w-4xl mx-auto">
    <div className="flex gap-3 items-start">
      <AssistantAvatar />
      <div className="flex-1 min-w-0 pt-0.5">
        <div className="text-[15px] leading-relaxed text-slate-800">
          <MarkdownContent content={value} />
        </div>
      </div>
    </div>
  </div>
));
TextBlock.displayName = 'TextBlock';

// ---------------------------------------------------------------------------
// messageRegistry
// ---------------------------------------------------------------------------

const createMessageRegistry = (toolBlockProps: Omit<ToolBlockProps, 'value'>) => ({
  thinking:   ({ value }: { value: string })           => <ReasoningBlock value={value} />,
  content:    ({ value }: { value: string })           => <TextBlock value={value} />,
  tool_calls: ({ value }: { value: CanonicalToolCall[] }) => <ToolBlock value={value} {...toolBlockProps} />,
});

// ---------------------------------------------------------------------------
// MessageBubble
// ---------------------------------------------------------------------------

export const MessageBubble = memo(({
  message,
  userId,
  delegationStatus,
  onToolComplete,
  toolResults,
}: MessageBubbleProps) => {
  const isUser = message.role === 'user' && !message.tool_result;

  const registry = useMemo(
    () => createMessageRegistry({ delegationStatus, onToolComplete, toolResults }),
    [delegationStatus, onToolComplete, toolResults]
  );

  const blocks = useMemo(() => {
    if (isUser) return null;

    const entries: [string, any][] = [
      ['thinking',   message.thinking],
      ['content',    message.content],
      ['tool_calls', message.tool_calls],
    ].filter(([, value]) => value !== undefined && value !== null && value !== '');

    return entries
      .map(([key, value]) => {
        const Block = registry[key as keyof typeof registry];
        if (!Block) return null;
        return <Block key={key} value={value as any} />;
      })
      .filter(Boolean);
  }, [message, registry, isUser]);

  if (!isUser && (!blocks || blocks.length === 0)) return null;

  return (
    <>
      {isUser ? (
        /* ── User bubble — gray pill, unchanged ── */
        <div className="py-3 max-w-4xl mx-auto">
          <div className="flex justify-end">
            <div className="bg-gray-100 rounded-2xl px-4 py-3 max-w-full sm:max-w-2xl">
              <div className="flex items-start gap-3">
                <div className="flex-shrink-0 w-6 h-6 rounded-full bg-gray-800 text-white flex items-center justify-center text-xs font-medium mt-0.5">
                  U
                </div>
                <div className="text-[15px] leading-relaxed text-gray-900 pt-0.5 break-all">
                  <MarkdownContent content={message.content ?? ''} />
                </div>
              </div>
            </div>
          </div>
        </div>
      ) : (
        blocks
      )}
    </>
  );
}, (prev, next) => {
  if (prev.userId !== next.userId) return false;
  if (prev.delegationStatus !== next.delegationStatus) return false;
  if (prev.toolResults !== next.toolResults) return false;
  return JSON.stringify(prev.message) === JSON.stringify(next.message);
});

MessageBubble.displayName = 'MessageBubble';

// ---------------------------------------------------------------------------
// ToolBlock
// ---------------------------------------------------------------------------

const ToolBlock = memo(({
  value,
  delegationStatus,
  onToolComplete,
  toolResults,
}: ToolBlockProps) => {
  const [openToolCalls, setOpenToolCalls] = useState<Record<number, boolean>>({});

  const toggleOpen = useCallback((index: number) => {
    setOpenToolCalls(prev => ({ ...prev, [index]: !prev[index] }));
  }, []);

  // If every tool call is a delegation call, nothing will render — skip the
  // avatar + wrapper entirely to avoid the ghost empty row.
  const visibleToolCalls = value.filter(tc => !tc.name.startsWith('delegate_to_'));
  if (visibleToolCalls.length === 0) return null;

  return (
    <div className="py-3 max-w-4xl mx-auto">
      <div className="flex gap-3 items-start">
        {/* Avatar spacer — aligns tool blocks under the assistant avatar column */}
        <AssistantAvatar />
        <div className="flex-1 min-w-0 space-y-2">
          {value.map((toolCall, idx) => {
            const savedResult = toolResults[toolCall.id] ?? null;
            return (
              <ToolCallRenderer
                key={toolCall.id ?? idx}
                toolCall={toolCall}
                delegationStatus={delegationStatus}
                onComplete={(result: string) => onToolComplete(toolCall.id, result)}
                isFinished={!!savedResult}
                savedResult={savedResult?.tool_result?.content ?? null}
                isOpen={openToolCalls[idx] || false}
                onToggle={() => toggleOpen(idx)}
              />
            );
          })}
        </div>
      </div>
    </div>
  );
});

ToolBlock.displayName = 'ToolBlock';

// ---------------------------------------------------------------------------
